import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import DropshippingExpandedContent, { DROPSHIPPING_EXPANDED_FAQS } from "@/components/DropshippingExpandedContent";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

function fmt(n: number) {
  return formatCurrencyValue(n, { maximumFractionDigits: 4 });
}
function fmt2(n: number) {
  return formatCurrencyValue(n, { maximumFractionDigits: 2 });
}


const FAQS = [
  { q: "What should I include in total product cost?", a: "Include all costs related to acquiring or producing the product: purchase price, shipping to warehouse, customs/import duties, storage fees, quality inspection costs, and any prep/packaging costs." },
  { q: "Why is knowing cost per unit important?", a: "Cost per unit is the foundation of your pricing strategy. Without it, you can't accurately calculate profit margin, set a competitive price, or evaluate supplier quotes. It's the starting point for all product economics." },
  { q: "How does cost per unit change with volume?", a: "Generally, the more units you order, the lower the cost per unit - due to bulk discounts and fixed shipping costs being spread across more items. Use this calculator to compare different order quantity scenarios." },
  { q: "Should I include overhead in cost per unit?", a: "For a complete picture, yes. Divide your monthly overhead (rent, software, labor) by units sold and add it to the direct cost per unit. This gives you the 'fully loaded' cost per unit used in true profit calculations." },
  { q: "What is the difference between COGS and cost per unit?", a: "Cost Per Unit (CPU) is the direct cost of one item. COGS (Cost of Goods Sold) is the total CPU  x  units sold during a period. COGS is used in financial reporting, while CPU is used for per-sale pricing decisions." },
  { q: "How do import duties affect cost per unit?", a: "Import duties are typically 0-30% of the product value, depending on the product category and country of origin. US Harmonized Tariff Schedule (HTS) codes determine duty rates. Always check applicable duties before pricing a product for sale." },
  { q: "What is economies of scale and how does it affect CPU?", a: "Economies of scale means your cost per unit decreases as order volume increases, because fixed costs (shipping, setup fees) are spread over more units. Ordering 1,000 units instead of 100 might cut your CPU in half." },
];

const EXPANDED_FAQS = DROPSHIPPING_EXPANDED_FAQS.costPerProduct;

export default function CostPerProductCalculator() {
  useCurrencyVersion();
  const [totalCost, setTotalCost] = useState(500);
  const [units, setUnits] = useState(100);

  const costPerUnit = units > 0 ? totalCost / units : 0;

  const bulkScenarios = [50, 100, 250, 500, 1000, 2500].map(u => ({
    units: u,
    cpu: totalCost / u,
    savings: costPerUnit > 0 ? ((costPerUnit - totalCost / u) / costPerUnit) * 100 : 0,
  }));

  return (
    <>
      <SEOHead
        title="Free Cost Per Product Calculator Online - Find Exact Unit Cost Instantly | CalcHive"
        description="Free online cost per product calculator. Divide your total batch cost by units to find your exact cost per unit instantly. 100% free for dropshippers and sellers, no signup required."
        canonical="/cost-per-product-calculator"
        keywords="free cost per product calculator, cost per unit calculator free online, unit cost calculator free, product cost calculator free, batch cost calculator free online"
        category="Dropshipping"
        faqs={EXPANDED_FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="inline-flex items-center gap-1.5 text-xs font-semibold uppercase tracking-widest text-emerald-600 dark:text-emerald-400 bg-emerald-50 dark:bg-emerald-950/50 px-3 py-1 rounded-full mb-4">Dropshipping</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Cost Per Product Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free cost per product calculator to calculate your exact cost per unit from any batch order. Enter the total cost and number of units to see your cost per product, then use the bulk comparison table to see how ordering more units reduces your per-unit cost. This cost per unit calculator free online also works as a unit cost calculator free, product cost calculator free, and batch cost calculator free online for accurate pricing and margin planning.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="total-cost" label="Total Batch Cost" value={totalCost} min={10} max={100000} step={10} onChange={setTotalCost} format={fmt2} testId="input-total-cost" />
            <SliderInput id="units-cpp" label="Number of Units" value={units} min={1} max={10000} step={1} onChange={setUnits} testId="input-units" helpText="units in this batch" />
          </div>
          <motion.div key={`${totalCost}-${units}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-emerald-500 to-emerald-700 rounded-2xl p-8 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Cost Per Unit</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-cost-per-unit">{fmt(costPerUnit)}</p>
              <p className="text-white/70 text-sm mt-1">{units.toLocaleString()} units - {fmt2(totalCost)} total</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[
                { label: "Total Cost", value: fmt2(totalCost) },
                { label: "Units", value: units.toLocaleString() },
                { label: "Cost  x  10 units", value: fmt2(costPerUnit * 10) },
              ].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-lg font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Cost Per Unit for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Cost per unit is the simplest and most important calculation in product economics. Divide your total order cost by the number of units received. The key is making sure your "total cost" includes every expense tied to getting that product ready for sale.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Cost Per Unit = Total Batch Cost  x  Number of Units</p>
            <p className="text-xs text-muted-foreground mt-2">Total Batch Cost includes:</p>
            <p>= Product Purchase Price + Shipping + Customs/Duties + Packaging + Inspection Fees</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Why Knowing Your Cost Per Product Matters</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Order Quantity", "Cost Per Unit", "vs. Current", "Savings at 100 Sales"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {bulkScenarios.map(({ units: u, cpu, savings }) => (
                  <tr key={u} className={`hover:bg-muted/30 ${u === units ? "bg-emerald-50 dark:bg-emerald-950/20" : ""}`}>
                    <td className="py-2.5 px-4 font-semibold text-foreground">{u.toLocaleString()} units {u === units ? "(current)" : ""}</td>
                    <td className="py-2.5 px-4 text-emerald-600 dark:text-emerald-400 font-semibold">{fmt(cpu)}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{savings > 0 ? `-ngs.toFixed(1)}%` : savings < 0 ? `+${Math.abs(savings).toFixed(1)}%` : "-"}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{fmt2((costPerUnit - cpu) * 100)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Unit Cost Tool for Every Seller and Dropshipper</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Cost Component", "Typical Range", "Notes"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Supplier product price", "Varies", "Your negotiated price per unit from manufacturer"],
                  ["International shipping (sea)", "2-8% of product value", "Slower but cheapest for large orders"],
                  ["International shipping (air)", "15-30% of product value", "Fast but expensive, for urgent orders"],
                  ["Import duties", "0-25% of product value", "Varies by product category and origin country"],
                  ["Customs brokerage", "$50-$200 per shipment", "Fixed fee, amortize across units"],
                  ["Packaging / prep", "$0.10-$2.00/unit", "Custom packaging, labeling, poly bags"],
                  ["Quality inspection", "$0.05-$0.30/unit", "Third-party factory inspection"],
                  ["FBA storage (Amazon)", "$0.56-$2.40/cubic ft/month", "Applies only to Amazon FBA sellers"],
                ].map(([component, range, notes]) => (
                  <tr key={component} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{component}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{range}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{notes}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <DropshippingExpandedContent kind="costPerProduct" />

        <section className="mb-8">
          <h2 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h2>
          <div className="space-y-3">{EXPANDED_FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/cost-per-product-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


